using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.Functions.Worker;
using Microsoft.Extensions.Logging;
using System.Data.SqlClient;
using System.Text;

public static class ReportingApi
{
    [Function("ReportingApi")]
    public static HttpResponseData Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequestData req,
        FunctionContext executionContext)
    {
        var logger = executionContext.GetLogger("ReportingApi");

        try
        {
            string dbServer = Environment.GetEnvironmentVariable("DB_SERVER");
            string dbName = Environment.GetEnvironmentVariable("DB_NAME");
            string user = Environment.GetEnvironmentVariable("USER");
            string password = Environment.GetEnvironmentVariable("PASSWORD");

            string sqlConnectionString = $"Server=tcp:{dbServer};Database={dbName};User Id={user};Password={password};";

            var queryString = req.Query;

            StringBuilder sb = new StringBuilder();

            foreach (var param in queryString)
            {
                if (!string.IsNullOrEmpty(param.Value))
                {
                    sb.Append($" AND {param.Key} LIKE '%{param.Value}%'");
                }
            }

            string sqlQuery = $"SELECT * FROM TABLE_NAME WHERE 1=1 {sb.ToString()}";

            using (SqlConnection connection = new SqlConnection(sqlConnectionString))
            {
                await connection.OpenAsync();

                using (SqlCommand command = new SqlCommand(sqlQuery, connection))
                {
                    using (SqlDataReader reader = await command.ExecuteReaderAsync())
                    {
                        StringBuilder sbData = new StringBuilder();
                        while (await reader.ReadAsync())
                        {
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                sbData.Append(reader[i].ToString() + " ");
                            }
                            sbData.Append("\n");
                        }

                        var response = req.CreateOdataResponse(HttpStatusCode.OK);
                        response.Headers.Add("Content-Type", "text/csv");

                        return response;
                    }
                }
            }
        }
        catch (Exception ex)
        {
            logger.LogError($"An error occurred: {ex.Message}");
            return req.CreateReponse(HttpStatusCode.InternalServerError);
        }
    }
}